import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const bets = await callMcpSkill({
    toolId,
    toolName: "find_moderate_probability_bets",
    args: {
      minPrice: 0.4,
      maxPrice: 0.6,
      minLiquidity: 1000000,
      limit: 20,
      sortBy: "liquidity",
      category: "all"
    }
  });

  const opportunities = Array.isArray(bets?.opportunities) ? bets.opportunities : [];
  const shortlist = opportunities
    .filter((o) => o && o.tokenId)
    .slice(0, 5)
    .map((o) => ({
      market: o.market,
      url: o.url,
      tokenId: o.tokenId,
      currentPrice: o.currentPrice,
      liquidity: o.liquidity,
      volume24h: o.volume24h,
      impliedProbability: o.impliedProbability
    }));

  const tokenIds = shortlist.map((o) => o.tokenId);

  let depthBatch = null;
  if (tokenIds.length > 0) {
    depthBatch = await callMcpSkill({
      toolId,
      toolName: "get_batch_orderbooks",
      args: { tokenIds }
    });
  }

  const orderbooks = depthBatch && depthBatch.orderbooks ? depthBatch.orderbooks : {};
  const results = shortlist.map((item) => {
    const ob = orderbooks[item.tokenId] || {};
    const bestAsk = typeof ob.bestAsk === "number" ? ob.bestAsk : null;
    const bestBid = typeof ob.bestBid === "number" ? ob.bestBid : null;
    const spread = typeof ob.spread === "number" ? ob.spread : null;
    const askDepth = typeof ob.askDepth === "number" ? ob.askDepth : null;
    const bidDepth = typeof ob.bidDepth === "number" ? ob.bidDepth : null;
    const midpoint = typeof ob.midpoint === "number" ? ob.midpoint : null;

    const tradability = (() => {
      if (spread === null || bestAsk === null || bestBid === null) return "unknown";
      if (spread <= 0.02 && ((askDepth || 0) + (bidDepth || 0)) >= 50000) return "strong";
      if (spread <= 0.05 && ((askDepth || 0) + (bidDepth || 0)) >= 20000) return "good";
      if (spread <= 0.08 && ((askDepth || 0) + (bidDepth || 0)) >= 10000) return "okay";
      return "thin";
    })();

    return {
      market: item.market,
      url: item.url,
      currentPrice: item.currentPrice,
      liquidity: item.liquidity,
      volume24h: item.volume24h,
      impliedProbability: item.impliedProbability,
      bestBid,
      bestAsk,
      spread,
      midpoint,
      askDepth,
      bidDepth,
      tradability,
      tradableInSizeRightNow: tradability === "strong" || tradability === "good",
      note:
        tradability === "strong"
          ? "Looks tradable in size: tight spread and meaningful depth."
          : tradability === "good"
          ? "Reasonably tradable in size: acceptable spread with usable depth."
          : tradability === "okay"
          ? "Tradable, but size may move price."
          : tradability === "thin"
          ? "Liquidity looks thin despite headline liquidity."
          : "Need quote data to judge depth."
    };
  });

  return {
    filter: {
      priceRange: "40% to 60%",
      minLiquidity: 1000000,
      marketCount: opportunities.length
    },
    summary: bets?.summary || null,
    candidatesReviewed: results.length,
    results,
    note: "The tradability assessment uses a past query’s fetched orderbook data from this turn, not real-time guarantees."
  };
}

