import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const result = await callMcpSkill({
    toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
    toolName: "find_arbitrage_opportunities",
    args: { category: "politics", limit: 20 }
  });

  const arb = Array.isArray(result.arbitrageOpportunities) ? result.arbitrageOpportunities : [];
  const wide = Array.isArray(result.wideSpreadMarkets) ? result.wideSpreadMarkets : [];
  const summary = result.summary || {};
  const methodology = result.methodology;

  const passiveCandidates = [
    ...arb.map((m) => ({
      market: m.market,
      url: m.url,
      type: "arbitrage",
      totalCost: m.totalCost,
      buyYesAt: m.buyYesAt,
      buyNoAt: m.buyNoAt,
      potentialEdge: m.potentialEdge,
      edgePercent: m.edgePercent,
      liquidity: m.liquidity,
      passiveOrderFit: m.totalCost !== undefined && m.totalCost < 1 ? "strong" : "n/a"
    })),
    ...wide.map((m) => ({
      market: m.market,
      url: m.url,
      type: "wide_spread",
      spread: m.spread,
      midPrice: m.midPrice,
      spreadPercent: m.spreadPercent,
      passiveOrderFit: "possible"
    }))
  ];

  return {
    fetchedAt: result.fetchedAt,
    scannedMarkets: result.scannedMarkets,
    summary,
    methodology,
    arbitrageOpportunities: arb,
    wideSpreadMarkets: wide,
    passiveOrderCandidates: passiveCandidates,
    takeaways: {
      arbitrageCount: summary.arbitrageCount,
      wideSpreadCount: summary.wideSpreadCount,
      note:
        arb.length > 0
          ? "Verified arbitrage-style setups were found; those are the best candidates for passive working orders."
          : "No verified arbitrage was found in this scan; any passive-order candidates come from wide spreads rather than guaranteed mispricing."
    }
  };
}

