export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  // Probe phase: fetch independent live-market discovery signals in parallel.
  // Keep parallelism only across different tools/endpoints, then do all selection locally.
  const batch = await callMcpSkillsParallel({
    label: "geopolitics-market-discovery",
    calls: [
      {
        key: "top_markets",
        toolId,
        toolName: "get_top_markets",
        args: {
          limit: 15,
          sortBy: "volume",
          category: "politics"
        }
      },
      {
        key: "trending_markets",
        toolId,
        toolName: "discover_trending_markets",
        args: {
          limit: 15,
          sortBy: "volume",
          category: "politics"
        }
      }
    ]
  });

  const topMarketsResult =
    batch.results.find((entry) => entry.key === "top_markets")?.status === "fulfilled"
      ? batch.results.find((entry) => entry.key === "top_markets").value
      : null;

  const trendingMarketsResult =
    batch.results.find((entry) => entry.key === "trending_markets")?.status === "fulfilled"
      ? batch.results.find((entry) => entry.key === "trending_markets").value
      : null;

  const topMarkets = Array.isArray(topMarketsResult?.markets) ? topMarketsResult.markets : [];
  const trendingMarkets = Array.isArray(trendingMarketsResult?.trendingMarkets)
    ? trendingMarketsResult.trendingMarkets
    : [];

  const combinedCandidates = [...topMarkets, ...trendingMarkets].filter(Boolean);

  // Deterministic semantic targeting against the user's requested scenario.
  const ranked = pickTopSemanticCandidates({
    target: "most active live geopolitics market",
    candidates: combinedCandidates,
    requiredTerms: ["live"],
    avoidTerms: ["resolved", "closed"],
    limit: 1
  });

  const selected = Array.isArray(ranked) ? ranked[0] : null;

  // Bounded fallback: if no clear geopolitics candidate is found, stop with explicit gaps.
