import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

const POLYMARKET_ID = "294100e8-c648-4e5f-a254-95a14b56e398";

function normalizeText(value) {
  return String(value || "").replace(/\s+/g, " ").trim();
}

function isTrumpOrFedMarket(item) {
  const title = normalizeText(item && item.title);
  return /trump/i.test(title) || /\bfed\b/i.test(title) || /federal reserve/i.test(title);
}

function scorePolymarketCandidate(item) {
  const title = normalizeText(item && item.title);
  const volume = typeof item?.volume === "number" ? item.volume : 0;
  const liquidity = typeof item?.liquidity === "number" ? item.liquidity : 0;
  const trend = typeof item?.trendScore === "number" ? item.trendScore : 0;
  const semanticBoost = isTrumpOrFedMarket(item) ? 1 : 0;
  return semanticBoost * 1000000000 + volume + liquidity + trend * 1000;
}

function toComparableSemantics(rules, kalshiMatch) {
  return {
    polymarketYes: normalizeText(rules?.rulesSummary?.resolvesYesIf || rules?.description || ""),
    polymarketNo: normalizeText(rules?.rulesSummary?.resolvesNoIf || ""),
    kalshiYes: normalizeText(kalshiMatch?.yesOutcomeMeans || ""),
    kalshiNo: normalizeText(kalshiMatch?.noOutcomeMeans || ""),
    polymarketResolutionSource: normalizeText(rules?.resolutionSource || ""),
    kalshiRules: normalizeText(kalshiMatch?.rules || "")
  };
}

function semanticsAligned(sem) {
  const pYes = sem.polymarketYes.toLowerCase();
