import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const result = await callMcpSkill({
    toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
    toolName: "find_moderate_probability_bets",
    args: {
      category: "politics",
      minPrice: 0.4,
      maxPrice: 0.75,
      minLiquidity: 10000,
      sortBy: "liquidity",
      limit: 10
    }
  });

  const opportunities = Array.isArray(result?.opportunities) ? result.opportunities : [];

  const rows = opportunities.map((op, idx) => ({
    rank: idx + 1,
    market: op.market,
    url: op.url,
    currentPrice: op.currentPrice,
    liquidity: op.liquidity,
    volume24h: op.volume24h,
    impliedProbability: op.impliedProbability,
    opportunityType: op.opportunityType,
    suggestedSide: op.suggestedSide,
    whyThisOpportunity: op.whyThisOpportunity
  }));

  return {
    summary: result?.summary,
    showing: `top ${rows.length} of ${opportunities.length} matching live politics markets`,
    opportunities: rows,
    fetchedAt: result?.fetchedAt
  };
}

