import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const result = await callMcpSkill({
    toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
    toolName: "find_moderate_probability_bets",
    args: {
      category: "politics",
      minPrice: 0.4,
      maxPrice: 0.75,
      minLiquidity: 10000,
      sortBy: "liquidity",
      limit: 10
    }
  });

  const opportunities = Array.isArray(result?.opportunities) ? result.opportunities : [];
  const politicalSignals = /(election|president|white house|congress|senate|house|prime minister|parliament|supreme court|government|trump|biden|iran|hungary|politic)/i;
  const excludedSignals = /(nba|cbb|basketball|football|soccer|gta|bitcoin|jesus|crypto)/i;

  const politicsOnly = opportunities.filter((op) => politicalSignals.test(`${op.market} ${op.url} ${op.category || ""}`) && !excludedSignals.test(`${op.market} ${op.url}`));

  const rows = politicsOnly.map((op, idx) => ({
    rank: idx + 1,
    market: op.market,
    url: op.url,
    currentPrice: op.currentPrice,
    liquidity: op.liquidity,
    volume24h: op.volume24h,
    impliedProbability: op.impliedProbability,
    opportunityType: op.opportunityType,
    suggestedSide: op.suggestedSide,
    lowerVolatilityThesis: op.liquidity >= 200000 && op.currentPrice >= 0.4 && op.currentPrice <= 0.75,
    whyThisOpportunity: op.whyThisOpportunity
  }));

  return {
    summary: {
      ...result?.summary,
      filteredToPolitics: politicsOnly.length,
      lowerVolatilityFilter: "liquidity >= 200k and YES price between 40-75¢"
    },
    showing: `top ${rows.length} of ${politicsOnly.length} politics-relevant markets from ${opportunities.length} raw matches`,
    opportunities: rows,
    fetchedAt: result?.fetchedAt
  };
}

